<style lang="scss" scoped>
.header-mobile-menu {
  position: relative;
  border-radius: var(--size-20);
  padding: var(--sp-40) var(--size-49);
  background: var(--white);

  &__close {
    position: absolute;
    top: var(--sp-10);
    right: var(--size-30);
    border: 0;
    background: transparent;
    padding: 0;
    cursor: pointer;
    line-height: 0;
  }

  &__list {
    list-style: none;
    margin: 0;
    padding: 0;
    display: flex;
    flex-direction: column;
    gap: var(--size-30);
  }

  &__item {
    width: 100%;
    border: 0;
    background: transparent;
    padding: var(--sp-4) 0;
    display: flex;
    align-items: flex-start;
    gap: var(--sp-20);
    cursor: pointer;
    text-align: left;
  }

  &__icon {
    flex: 0 0 auto;
    width: var(--size-25);
    min-height: var(--size-25);
    display: inline-flex;
    align-items: center;
    justify-content: center;
  }

  &__label {
    font-family: var(--font-family);
    font-weight: var(--font-semi-bold);
    font-size: clamp(20px, calc(20px + 5 * ((100vw - 430px) / 594)), 25px);
    color: var(--black);
    line-height: 1.2;
  }
}
</style>
